     1→import React, { useState, useEffect, useCallback } from 'react';
     2→import { User, AnalysisResult, SMCContent, GeneratedSolution } from './types';
     3→import { analyzeUrl } from './services/analyzer';
     4→import Home from './pages/Home';
     5→import Login from './pages/Login';
     6→import Dashboard from './pages/Dashboard';
     7→import Projects from './pages/Projects';
     8→import Analyze from './pages/Analyze';
     9→import SMCStudio from './pages/SMCStudio';
    10→import KnowledgeExplorer from './pages/KnowledgeExplorer';
    11→import Benchmark from './pages/Benchmark';
    12→import Recharge from './pages/Recharge';
    13→import Plans from './pages/Plans';
    14→import Account from './pages/Account';
    15→import { 
    16→  Home as HomeIcon, 
    17→  LayoutDashboard, 
    18→  ScanLine, 
    19→  FolderOpen, 
    20→  Sparkles, 
    21→  Fuel, 
    22→  Share2, 
    23→  User as UserIcon,
    24→  LogOut,
    25→  Network,
    26→  BarChart3,
    27→  ChevronRight,
    28→  CreditCard
    29→} from 'lucide-react';
    30→
    31→const App: React.FC = () => {
    32→  const [currentView, setCurrentView] = useState<string>('home');
    33→  const [user, setUser] = useState<User | null>(null);
    34→  const [history, setHistory] = useState<AnalysisResult[]>([]);
    35→  const [isAnalyzing, setIsAnalyzing] = useState(false);
    36→  const [analysisData, setAnalysisData] = useState<AnalysisResult | null>(null);
    37→  const [smcLibrary, setSmcLibrary] = useState<SMCContent[]>([]);
    38→
    39→  useEffect(() => {
    40→    const savedHistory = localStorage.getItem('aeo_history_v2');
    41→    if (savedHistory) setHistory(JSON.parse(savedHistory));
    42→    
    43→    const savedLibrary = localStorage.getItem('aeo_library_v2');
    44→    if (savedLibrary) setSmcLibrary(JSON.parse(savedLibrary));
    45→
    46→    const savedUser = localStorage.getItem('aeo_user');
    47→    if (savedUser) setUser(JSON.parse(savedUser));
    48→  }, []);
    49→
    50→  useEffect(() => {
    51→    localStorage.setItem('aeo_history_v2', JSON.stringify(history));
    52→  }, [history]);
    53→
    54→  useEffect(() => {
    55→    localStorage.setItem('aeo_library_v2', JSON.stringify(smcLibrary));
    56→  }, [smcLibrary]);
    57→
    58→  useEffect(() => {
    59→    if (user) localStorage.setItem('aeo_user', JSON.stringify(user));
    60→    else localStorage.removeItem('aeo_user');
    61→  }, [user]);
    62→
    63→  const handleLogin = (loggedInUser: User) => {
    64→    setUser(loggedInUser);
    65→    setCurrentView('dashboard');
    66→  };
    67→
    68→  const handleLogout = () => {
    69→    setUser(null);
    70→    setCurrentView('home');
    71→  };
    72→
    73→  const handleAnalyze = async (url: string) => {
    74→    setIsAnalyzing(true);
    75→    try {
    76→      const result = await analyzeUrl(url);
    77→      setAnalysisData(result);
    78→      setHistory(prev => [result, ...prev]);
    79→      setCurrentView('projects');
    80→    } catch (error) {
    81→      console.error("Analysis failed", error);
    82→      alert("Erreur lors de l'analyse.");
    83→    } finally {
    84→      setIsAnalyzing(false);
    85→    }
    86→  };
    87→
    88→  const handleDeductCredits = (amount: number): boolean => {
    89→    if (!user) {
    90→      setCurrentView('login');
    91→      return false;
    92→    }
    93→    if (user.credits < amount) {
    94→      alert("GTO Gas insuffisant.");
    95→      setCurrentView('recharge');
    96→      return false;
    97→    }
    98→    setUser({ ...user, credits: user.credits - amount });
    99→    return true;
   100→  };
   101→
   102→  const handleSaveSolution = useCallback((analysisId: string, recId: string, solution: GeneratedSolution) => {
   103→    const timestamp = new Date().toISOString();
   104→    const solutionWithMeta = { ...solution, timestamp };
   105→    
   106→    setHistory(prev => prev.map(item => {
   107→      if (item.timestamp === analysisId) {
   108→        return {
   109→          ...item,
   110→          generatedSolutions: {
   111→            ...(item.generatedSolutions || {}),
   112→            [recId]: solutionWithMeta
   113→          }
   114→        };
   115→      }
   116→      return item;
   117→    }));
   118→  }, []);
   119→
   120→  const NavItem = ({ label, icon: Icon, view }: { label: string, icon: any, view: string }) => (
   121→    <button 
   122→      onClick={() => setCurrentView(view)}
   123→      className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm transition-all duration-200 ${
   124→        currentView === view
   125→          ? 'bg-primary/10 text-primary font-bold shadow-sm' 
   126→          : 'text-gray-400 hover:text-white hover:bg-white/5 font-medium'
   127→      }`}
   128→    >
   129→      <Icon size={18} />
   130→      <span>{label}</span>
   131→    </button>
   132→  );
   133→
   134→  return (
   135→    <div className="min-h-screen flex flex-col font-sans text-gray-100 bg-black overflow-x-hidden">
   136→      <nav className="border-b border-white/5 bg-black/80 backdrop-blur-md sticky top-0 z-50 h-16">
   137→        <div className="max-w-7xl mx-auto px-4 h-full flex items-center justify-between">
   138→          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setCurrentView('home')}>
   139→            <div className="w-8 h-8 rounded-lg bg-primary flex items-center justify-center text-black font-bold font-serif text-xl">C</div>
   140→            <span className="font-serif text-xl font-bold tracking-tight">CitedBy.ai</span>
   141→          </div>
   142→
   143→          <div className="flex items-center gap-4">
   144→            {user ? (
   145→              <div className="flex items-center gap-4">
   146→                <button 
   147→                  onClick={() => setCurrentView('recharge')}
   148→                  className="hidden md:flex items-center gap-1.5 bg-white/5 px-3 py-1.5 rounded-full border border-white/10 hover:border-primary/50 transition-colors"
   149→                >
   150→                  <Fuel size={14} className="text-primary" />
   151→                  <span className="text-sm font-bold tracking-tighter">{user.credits} Gas</span>
   152→                </button>
   153→                <div className="flex items-center gap-3 cursor-pointer" onClick={() => setCurrentView('account')}>
   154→                  <div className="w-9 h-9 rounded-full bg-primary/10 border border-primary/20 flex items-center justify-center font-bold text-primary">
   155→                    {user.name.charAt(0).toUpperCase()}
   156→                  </div>
   157→                </div>
   158→              </div>
   159→            ) : (
   160→              <button onClick={() => setCurrentView('login')} className="text-sm font-bold bg-white text-black px-5 py-2 rounded-lg hover:bg-gray-200 transition-all">
   161→                Connexion
   162→              </button>
   163→            )}
   164→          </div>
   165→        </div>
   166→      </nav>
   167→
   168→      <div className="flex-grow flex flex-col md:flex-row max-w-7xl mx-auto w-full relative">
   169→        {user && (
   170→          <aside className="hidden md:flex w-64 flex-col pr-6 py-6 sticky top-16 h-[calc(100vh-4rem)] overflow-y-auto custom-scrollbar">
   171→            <div className="bg-[#09090b] border border-white/10 rounded-2xl p-4 space-y-1 shadow-2xl">
   172→              <NavItem label="Nouvel Audit" icon={ScanLine} view="analyze" />
   173→              <NavItem label="Dashboard" icon={LayoutDashboard} view="dashboard" />
   174→              <NavItem label="Projets" icon={FolderOpen} view="projects" />
   175→              <div className="my-2 border-t border-white/5 mx-2"></div>
   176→              <NavItem label="Knowledge Graph" icon={Network} view="explorer" />
   177→              <NavItem label="Benchmarking" icon={BarChart3} view="benchmark" />
   178→              <NavItem label="Outils Génératifs" icon={Sparkles} view="smc-studio" />
   179→              <div className="my-2 border-t border-white/5 mx-2"></div>
   180→              <NavItem label="Plan & Facturation" icon={CreditCard} view="plans" />
   181→              <NavItem label="GTO Gas" icon={Fuel} view="recharge" />
   182→              <NavItem label="Compte" icon={UserIcon} view="account" />
   183→              <button onClick={handleLogout} className="w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm text-red-400 hover:bg-red-400/5 transition-all">
   184→                <LogOut size={18} /> <span>Déconnexion</span>
   185→              </button>
   186→            </div>
   187→          </aside>
   188→        )}
   189→
   190→        <main className="flex-1 w-full min-w-0 pb-20 md:pb-0">
   191→          {currentView === 'home' && <Home onNavigate={(v: any) => setCurrentView(v)} user={user} />}
   192→          {currentView === 'login' && <Login onLogin={handleLogin} onBack={() => setCurrentView('home')} />}
   193→          {currentView === 'dashboard' && <Dashboard history={history} onView={(res) => { setAnalysisData(res); setCurrentView('projects'); }} onNavigate={(v: any) => setCurrentView(v)} />}
   194→          {currentView === 'analyze' && <Analyze onAnalyze={handleAnalyze} isAnalyzing={isAnalyzing} />}
   195→          {currentView === 'projects' && (
   196→            <Projects 
   197→              history={history} 
   198→              user={user} 
   199→              onDeductCredits={handleDeductCredits} 
   200→              onSaveSolution={handleSaveSolution}
   201→              onNavigateToRecharge={() => setCurrentView('recharge')}
   202→              onNewAnalysis={() => setCurrentView('analyze')}
   203→              initialAnalysis={analysisData}
   204→            />
   205→          )}
   206→          {currentView === 'explorer' && <KnowledgeExplorer analysis={analysisData || history[0]} />}
   207→          {currentView === 'benchmark' && <Benchmark history={history} />}
   208→          {currentView === 'smc-studio' && (
   209→            <SMCStudio 
   210→              user={user} 
   211→              analysisData={analysisData}
   212→              onDeductCredits={handleDeductCredits} 
   213→              library={smcLibrary} 
   214→              onAddToLibrary={(item) => setSmcLibrary(prev => [item, ...prev])} 
   215→            />
   216→          )}
   217→          {currentView === 'recharge' && (
   218→            <Recharge user={user} onRecharge={(amt, lvl) => { if(user) setUser({...user, credits: user.credits + amt, plan: lvl}); setCurrentView('dashboard'); }} onBack={() => setCurrentView('dashboard')} />
   219→          )}
   220→          {currentView === 'plans' && (
   221→            <Plans 
   222→              user={user} 
   223→              onSelectPlan={(plan) => alert(`Plan ${plan} sélectionné (Mode démo)`)} 
   224→              onNavigate={(v) => setCurrentView(v)}
   225→            />
   226→          )}
   227→          {currentView === 'account' && <Account user={user} onLogout={handleLogout} onNavigate={(v: any) => setCurrentView(v)} />}
   228→        </main>
   229→      </div>
   230→
   231→      {user && (
   232→        <div className="md:hidden fixed bottom-0 left-0 right-0 bg-black/90 backdrop-blur-lg border-t border-white/10 z-50 h-16 flex items-center justify-around px-4">
   233→          <button onClick={() => setCurrentView('dashboard')} className={currentView === 'dashboard' ? 'text-primary' : 'text-gray-500'}><LayoutDashboard size={20} /></button>
   234→          <button onClick={() => setCurrentView('projects')} className={currentView === 'projects' ? 'text-primary' : 'text-gray-500'}><FolderOpen size={20} /></button>
   235→          <button onClick={() => setCurrentView('analyze')} className={currentView === 'analyze' ? 'text-primary' : 'text-gray-500'}><ScanLine size={20} /></button>
   236→          <button onClick={() => setCurrentView('smc-studio')} className={currentView === 'smc-studio' ? 'text-primary' : 'text-gray-500'}><Sparkles size={20} /></button>
   237→          <button onClick={() => setCurrentView('account')} className={currentView === 'account' ? 'text-primary' : 'text-gray-500'}><UserIcon size={20} /></button>
   238→        </div>
   239→      )}
   240→    </div>
   241→  );
   242→};
   243→
   244→export default App;

