     2→import React, { useState } from 'react';
     3→import { Search, Loader2, ShieldCheck, TrendingUp } from 'lucide-react';
     4→
     5→interface Props {
     6→  onAnalyze: (url: string) => void;
     7→  isAnalyzing: boolean;
     8→}
     9→
    10→const Analyze: React.FC<Props> = ({ onAnalyze, isAnalyzing }) => {
    11→  const [url, setUrl] = useState('');
    12→
    13→  const handleSubmit = (e: React.FormEvent) => {
    14→    e.preventDefault();
    15→    if (url && !isAnalyzing) onAnalyze(url);
    16→  };
    17→
    18→  return (
    19→    <div className="max-w-4xl mx-auto px-4 py-32 flex flex-col items-center">
    20→      <div className="text-center mb-12 space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
    21→        <h1 className="text-4xl md:text-5xl font-serif font-bold">Audit de visibilité IA</h1>
    22→        <p className="text-gray-400 text-lg">Entrez votre URL pour découvrir votre score AEO.</p>
    23→      </div>
    24→
    25→      <form onSubmit={handleSubmit} className="w-full max-w-2xl relative group">
    26→        <div className="absolute inset-0 bg-primary/20 blur-3xl rounded-full opacity-20 -z-10 group-focus-within:opacity-40 transition-opacity"></div>
    27→        <div className="flex items-center p-2 bg-white/5 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl transition-all focus-within:border-primary/50">
    28→          <Search className="text-gray-500 ml-4 shrink-0" size={24} />
    29→          <input 
    30→            type="url" required placeholder="https://votre-site.com" 
    31→            className="w-full bg-transparent border-none focus:ring-0 text-white placeholder-gray-600 text-lg px-4 py-4 outline-none"
    32→            value={url} onChange={(e) => setUrl(e.target.value)}
    33→          />
    34→          <button 
    35→            type="submit" disabled={isAnalyzing}
    36→            className="px-8 py-4 bg-primary text-black font-bold rounded-xl hover:bg-emerald-400 transition-all disabled:opacity-50 shrink-0"
    37→          >
    38→            {isAnalyzing ? <Loader2 className="animate-spin" /> : 'Analyser'}
    39→          </button>
    40→        </div>
    41→        
    42→        <div className="flex justify-center gap-8 mt-8 text-xs text-gray-500 uppercase tracking-widest font-bold">
    43→          <span className="flex items-center gap-2"><ShieldCheck size={14} className="text-primary"/> Scan Sécurisé</span>
    44→          <span className="flex items-center gap-2"><TrendingUp size={14} className="text-primary"/> 50+ Critères</span>
    45→        </div>
    46→      </form>
    47→    </div>
    48→  );
    49→};
    50→
    51→export default Analyze;
