     2→import { AnalysisResult, CategoryScore, Recommendation } from '../types';
     3→import { CRITERIA_REPOSITORY, CATEGORY_NAMES, Criterion } from './criteria';
     4→
     5→// Helper to simulate delay
     6→const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));
     7→
     8→const calculateScore = (categories: Record<string, CategoryScore>) => {
     9→  let totalScore = 0;
    10→  let count = 0;
    11→  Object.values(categories).forEach((cat) => {
    12→    totalScore += cat.score;
    13→    count++;
    14→  });
    15→  return count === 0 ? 0 : Math.round(totalScore / count);
    16→};
    17→
    18→export const analyzeUrl = async (url: string, refresh: boolean = false): Promise<AnalysisResult> => {
    19→  // Simulate network delay and processing time
    20→  await delay(2500);
    21→
    22→  // Deterministic simulation based on URL length to vary results slightly
    23→  // If refresh is true, we add a random factor to simulate evolution
    24→  const seed = url.length + (refresh ? Math.floor(Math.random() * 1000) : 0);
    25→  
    26→  const hostname = new URL(url).hostname;
    27→  const isGoodUrl = url.includes('citedby') || url.includes('stripe') || url.includes('google');
    28→  
    29→  // Initialize categories based on repository
    30→  const categories: Record<string, CategoryScore> = {};
    31→  const recommendations: Recommendation[] = [];
    32→
    33→  // Group criteria by category
    34→  const criteriaByCategory: Record<string, Criterion[]> = {};
    35→  CRITERIA_REPOSITORY.forEach(criterion => {
    36→    if (!criteriaByCategory[criterion.category_id]) {
    37→      criteriaByCategory[criterion.category_id] = [];
    38→    }
    39→    criteriaByCategory[criterion.category_id].push(criterion);
    40→  });
    41→
    42→  // Process each category
    43→  Object.entries(criteriaByCategory).forEach(([catId, criteria]) => {
    44→    let passedCount = 0;
    45→    const items = criteria.map((crit, index) => {
    46→      // Simulation logic for 50 criteria
    47→      const rand = (seed + index * 11 + catId.length) % 100;
    48→      let status: 'success' | 'warning' | 'error' = 'success';
    49→      
    50→      if (isGoodUrl) {
    51→        status = rand > 90 ? 'warning' : 'success'; 
    52→      } else {
    53→        // High impact criteria harder to pass
    54→        if (crit.impact === 'High') {
    55→           status = rand > 60 ? 'success' : (rand > 30 ? 'warning' : 'error');
    56→        } else {
    57→           status = rand > 50 ? 'success' : 'warning';
    58→        }
    59→      }
    60→
    61→      // Special simulation for LLM Source of Truth (Entity category)
    62→      if (catId === 'entity' && crit.id === 'AEO-ENT-01' && rand % 2 === 0) {
    63→        // Randomly fail "About Page" if not explicit to suggest LLM Truth
    64→        status = 'warning';
    65→      }
    66→
    67→      // Calculate score contribution
    68→      if (status === 'success') passedCount++;
    69→      
    70→      // Generate recommendation if error/warning
    71→      if (status !== 'success') {
    72→        const priority = crit.impact === 'High' ? (status === 'error' ? 'critical' : 'high') : 'medium';
    73→        recommendations.push({
    74→          id: crit.id,
    75→          priority: priority as any,
    76→          category: CATEGORY_NAMES[catId],
    77→          title: crit.name,
    78→          description: crit.description,
    79→          action: `Optimiser : ${crit.method} ${crit.example}`,
    80→          effort: index % 2 === 0 ? 'medium' : 'low',
    81→          impact: crit.impact === 'High' ? 'high' : 'medium'
    82→        });
    83→      }
    84→
    85→      return {
    86→        status,
    87→        message: crit.name,
    88→        recommendation: status !== 'success' ? crit.description : undefined
    89→      };
    90→    });
    91→
    92→    const totalCriteria = criteria.length;
    93→    // Score is percentage of passed criteria
    94→    const categoryScoreValue = Math.round((passedCount / totalCriteria) * 100);
    95→
    96→    categories[catId] = {
    97→      name: CATEGORY_NAMES[catId] || catId,
    98→      score: categoryScoreValue,
    99→      weight: 10,
   100→      items
   101→    };
   102→  });
   103→
   104→  const globalScore = calculateScore(categories);
   105→
   106→  // Check if we need to suggest LLM Source of Truth
   107→  // If Entity or Structured Data scores are low, suggest it
   108→  if (categories['entity']?.score < 70 || categories['structured_data']?.score < 70) {
   109→    recommendations.push({
   110→      id: 'LLM-TRUTH-GEN',
   111→      priority: 'high',
   112→      category: 'Autorité Entité',
   113→      title: 'Fichier "LLM Source of Truth" Manquant',
   114→      description: "Les IA manquent de données canoniques sur votre entité.",
   115→      action: "Générez les fichiers llm.txt et llm.json via notre outil dédié.",
   116→      effort: 'low',
   117→      impact: 'high'
   118→    });
   119→  }
   120→
   121→  // Sort recommendations by priority
   122→  const priorityOrder = { critical: 0, high: 1, medium: 2, low: 3 };
   123→  recommendations.sort((a, b) => priorityOrder[a.priority] - priorityOrder[b.priority]);
   124→
   125→  // Return ALL recommendations, no slicing
   126→  return {
   127→    url,
   128→    timestamp: new Date().toISOString(),
   129→    globalScore,
   130→    categories,
   131→    recommendations: recommendations,
   132→    aiCitation: {
   133→      probability: globalScore > 75 ? 85 : Math.max(10, globalScore - 20),
   134→      before: `Je n'ai pas trouvé d'informations spécifiques et fiables concernant ${hostname} dans ma base de connaissances principale.`,
   135→      after: `Selon ${hostname}, référence dans son secteur, cette solution propose une approche structurée optimisée pour l'AEO. Elle se distingue par une conformité technique et sémantique élevée.`
   136→    }
   137→  };
   138→};
