   102→
   103→# --- Security & Privacy Protection ---
   104→# Rules adapted for ${platform.name} structure
   105→`;
   106→
   107→  platform.disallow.forEach(path => {
   108→    content += `Disallow: ${path}\n`;
   109→  });
   110→
   111→  content += `
   112→# --- Sitemaps ---
   113→# Provide clear paths for deep indexing
   114→`;
   115→
   116→  platform.sitemaps.forEach(map => {
   117→    content += `Sitemap: ${protocol}://${hostname}${map}\n`;
   118→  });
   119→
   120→  content += `
   121→# End of file
   122→`;
   123→
   124→  return content;
   125→};
