     4→interface ScoreRingProps {
     5→  score: number;
     6→  size?: number;
     7→  strokeWidth?: number;
     8→}
     9→
    10→const ScoreRing: React.FC<ScoreRingProps> = ({ score, size = 120, strokeWidth = 8 }) => {
    11→  const [animatedScore, setAnimatedScore] = useState(0);
    12→  const radius = (size - strokeWidth) / 2;
    13→  const circumference = radius * 2 * Math.PI;
    14→  const offset = circumference - (animatedScore / 100) * circumference;
    15→
    16→  useEffect(() => {
    17→    const timer = setTimeout(() => setAnimatedScore(score), 100);
    18→    return () => clearTimeout(timer);
    19→  }, [score]);
    20→
    21→  const getColor = (s: number) => {
    22→    if (s >= 80) return '#10b981';
    23→    if (s >= 60) return '#f59e0b';
    24→    return '#ef4444';
    25→  };
    26→
    27→  return (
    28→    <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
    29→      <svg width={size} height={size} className="transform -rotate-90">
    30→        <circle cx={size/2} cy={size/2} r={radius} stroke="#ffffff10" strokeWidth={strokeWidth} fill="transparent" />
    31→        <circle 
    32→          cx={size/2} cy={size/2} r={radius} stroke={getColor(animatedScore)} strokeWidth={strokeWidth} 
    33→          fill="transparent" strokeDasharray={circumference} strokeDashoffset={offset} strokeLinecap="round"
    34→          className="transition-all duration-1000 ease-out"
    35→        />
    36→      </svg>
    37→      <div className="absolute flex flex-col items-center">
    38→        <span className="text-3xl font-bold" style={{ color: getColor(animatedScore) }}>{animatedScore}</span>
    39→        <span className="text-[10px] text-gray-500 uppercase tracking-tighter">AEO Score</span>
    40→      </div>
    41→    </div>
    42→  );
    43→};
    44→
    45→export default ScoreRing;
